(window.webpackJsonp=window.webpackJsonp||[]).push([[53],{680:function(n,o){n.exports="\x3c!-- \ntitle: 08-Pytorch基础\nsort: \n--\x3e \n\n## 计算\n\n```python\nimport torch.nn as nn\n\n\n# 算均方误差\nx = torch.ones(1)\nw = torch.full([1],3.)\nloss_func = nn.MSELoss()\n\n\n# 将w变为可导\nw.requires_grad_()\n# 更新计算图 (predict, label)\nmse = loss_func(torch.ones(1),x*w)\n\n# 求导\ntorch.autograd.grad(mse,[w])\n# 更简单的向后传播\nmse.backward()\nw.grad\n\n# 归一化\nx = torch.tensor([1,2,3],dtype=torch.float)\nsoftmax1 = nn.Softmax(dim=0)\nsoftmax1(x)\n```\n\n\n\n"}}]);